    ('cat_parts_of_me_books', 3, 3, 'visible', true, true, 'Best for finger and toe rhyme', 'Ten Little Fingers and Ten Little Toes', 'Walker Books', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9781406331264/isbn/Ten-Little-Fingers-and-Ten-Little-Toes-by-Mem-Fox.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Mem Fox Ten Little Fingers and Ten Little Toes board book celebrating babies hands and feet with warm rhyme and clear pictures on sturdy boards.', 'Fingers and toes are the body parts they can finally see and grab. Count aloud while they hold a foot; the book is the refrain. Keep one short count, then stop while the shared look still feels friendly on the sofa.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 4, 4, 'visible', true, true, 'Best for move your body pages', 'From Head to Toe', 'Eric Carle', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9780140563788/isbn/From-Head-to-Toe-by-Eric-Carle.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Eric Carle From Head to Toe board book inviting babies to copy simple animal movements from head nods to foot stamps with a parent on the mat.', 'Body awareness grows when movement joins the name. Do one animal action on the mat, then close the book before it becomes a workout. Stay close, keep it playful, and stop while smiles are still easy after that single action.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 5, 5, 'visible', true, true, 'Best for nose toes play', 'The Nose, Toes and Tummy Book', 'Andersen Press', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9781839135897/isbn/The-Nose-Toes-and-Tummy-Book-by-Sally-Nicholls.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Sally Nicholls Nose Toes and Tummy board book that invites families to press, tickle and name body parts with bold friendly art on sturdy pages.', 'Playful prompts beat dry labels. Beep a nose, then kiss a tummy; the page is permission to be silly together during nose toes play on the mat. Keep one prompt per sitting and stop while giggles are still easy rather than racing every page.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 6, 6, 'visible', true, true, 'Best for face looking', 'Baby Touch: Faces', 'Ladybird', 'Penguin UK', 'https://www.penguin.co.uk/books/313409/baby-touch-faces-a-black-and-white-book-by-ladybird/9780241391723', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'A Ladybird Baby Touch Faces board book of large friendly faces, the first body map many babies notice before hands and feet on the page.', 'Faces are still the strongest body cue. Point to eyes and mouth on the page, then on your own face, then stop. Keep turns short on the sofa and put the book away while the shared look still feels friendly.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 7, 7, 'visible', true, true, 'Best for animal body shapes', 'Baby Touch: Animals', 'Ladybird', 'Penguin UK', 'https://www.penguin.co.uk/books/313410/baby-touch-animals-a-black-and-white-book-by-ladybird/9780241391730', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'A Ladybird Baby Touch Animals board book with clear animal shapes that invite pointing at heads, tails and feet beside your babys own body.', 'Animals give a second route into body words when face books feel finished. Name one part per page, then close the covers. Stay close on the sofa and stop while the shared look still feels friendly rather than finishing every animal shape tonight.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 8, 8, 'visible', true, true, 'Best for textured puppy body', 'That''s Not My Puppy...', 'Usborne', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9781474959063/isbn/Thats-Not-My-Puppy-by-Fiona-Watt.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Usborne That is Not My Puppy with soft textured patches that invite stroking ears, tummies and paws while you name the body part aloud together.', 'Texture plus naming keeps hands busy while mouths want everything on the puppy body pages. One patch per sitting is enough. Close the book while the shared look still feels friendly and save the rest of the patches for another awake spell.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 9, 9, 'visible', true, true, 'Best for textured cat body', 'That''s Not My Cat...', 'Usborne', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9781805072485/isbn/Thats-Not-My-Cat-by-Fiona-Watt.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Usborne That is Not My Cat with soft textured patches for ears, whiskers and paws, a second texture set for naming body parts on animals.', 'If Puppy is sticky with milk, Cat keeps the same refrain with new textured patches on the body pages. Cap Usborne at two on this card so the shelf does not fill with the same pattern. Stop while the shared look still feels friendly.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_parts_of_me_books', 10, 10, 'visible', true, true, 'Best for colour animal chorus', 'Brown Bear, Brown Bear, What Do You See?', 'Puffin', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9780241137291/isbn/Brown-Bear-Brown-Bear-What-Do-You-See-by-Bill-Martin.html', NULL, 'See retailer', 'in_stock', 'Baby and toddler', 'Brown Bear colour animal chorus for pointing at eyes, mouths and feet in bold Carle pictures during a short shared look on the sofa.', 'Not a pure body book, but pointing at animal faces and feet still trains the look and name habit with a colour animal chorus. Use when dedicated body titles are all sticky. Keep one animal, then stop while the shared look still feels friendly.', 'Shared looking and early chat at 4-6m.', 'Supervise; boards can get chewed.', 'buy', true, 'Good gift if library copy not already loved.', 'Families often own several board books already - ask first.', 'Awake shared reading only; not for the cot.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 1, 1, 'visible', true, false, 'Best for several grab points', 'Lamaze Freddie The Firefly Soft Toy', 'Lamaze', 'Ocado', 'https://www.ocado.com/products/lamaze-freddie-the-firefly-buggy-toy-0mths/73143011', NULL, '£14.39', 'in_stock', '0–12 months', 'A soft Lamaze Freddie Firefly with layered wings, a peekaboo mirror, clinking rings and a tethered ladybird teether, plus a clip for the pram or playmat edge.', 'Hands are aiming more now, not just brushing past toys. Freddie gives several places to grab and something to mouth once the hold sticks. Clip him where they can see him during floor play so a reach has a clear target within arm reach on the mat.', 'Multi-texture reach target.', 'Check stitching.', 'buy', true, 'Classic gift.', 'Ask before doubling.', 'Supervised.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 2, 2, 'visible', true, true, 'Best for soft octopus grabs', 'Lamaze Captain Calamari', 'Lamaze', 'Ocado', 'https://www.ocado.com/products/lamaze-captain-calamari-buggy-toy-0mths/353093011', NULL, 'See Hamleys', 'in_stock', '0 months+', 'A soft Lamaze Captain Calamari octopus with long grabable legs and mixed textures, sized so both hands can catch hold during supervised floor or pram play.', 'Single hand brushes are turning into proper holds. Long soft legs give a bigger target when aim is still wobbly. Keep play on the mat so a triumphant grab does not end under the sofa cushions again, and stay within arm reach the whole time.', 'Large bilateral grab.', 'Bulky in a small bag.', 'buy', true, 'Fun character gift.', 'Lamaze capped at two.', 'Supervised.', 'good', ARRAY[]::text[], 'check_price'),
    ('cat_reach_grab_toys', 3, 3, 'visible', true, true, 'Best for rubber giraffe grabs', 'Sophie La Girafe Original Teether', 'Sophie La Girafe', 'Ocado', 'https://www.ocado.com/products/sophie-la-girafe-original-teether/78496011', NULL, '£15.99', 'in_stock', 'From birth', 'The original Sophie La Girafe natural rubber teether with soft limbs and a gentle squeak, light enough for small hands to lift toward the mouth during floor play.', 'Reaching often ends in the mouth at this age. Soft Sophie legs give something to catch and chew without hard plastic edges. Wipe clean only; she is not dishwasher gear for the steriliser cycle. Keep sessions short and stay within arm reach on the floor.', 'Grab that becomes gum work.', 'Surface clean only.', 'buy', true, 'Check duplicates.', 'Common shower gift.', 'Inspect wear.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 4, 4, 'visible', true, true, 'Best for textured ring grabs', 'Sophie la Girafe So Pure Soft Teether', 'Sophie La Girafe', 'Coolshop', 'https://www.coolshop.co.uk/product/sophie-la-girafe-so-pure-teether-soft-200318/A4G7JH/', NULL, 'See Hamleys', 'in_stock', 'From birth', 'A Sophie la Girafe So Pure soft teething ring with two textured rings, light for small hands to lift and mouth on the playmat during floor play.', 'Some babies prefer a ring they can slide and chew over a giraffe body. The textures reward a successful grab with something interesting on the gums. Keep this as the second Sophie shape, not a third Sophie buy in the same basket this month.', 'Ring grab style.', 'Sophie capped at two.', 'buy', true, 'If classic Sophie owned.', 'Sophie max two.', 'Supervised.', 'good', ARRAY[]::text[], 'none'),
    ('cat_reach_grab_toys', 5, 5, 'visible', true, true, 'Best for linking grab packs', 'Playgro Jungle Friends Gift Pack', 'Playgro', 'Coolshop UK', 'https://www.coolshop.co.uk/product/playgro-jungle-friends-gift-pack-10182436/AD6X5Q/', NULL, '£23.00', 'in_stock', '0 months+', 'A Playgro Jungle Friends gift pack with wrist rattles, soft foot finders and three textured linking teethers, giving several grabable pieces for supervised floor play.', 'A single toy can bore a determined grabber. This pack spreads reaches across links, wrists and feet without buying five separate pieces. Use the linking teethers on the mat first if the soft foot pieces feel fiddly at four months old.', 'Multiple grab pieces.', 'Overlaps kick-sock card.', 'buy', true, 'Multi-piece gift.', 'Skip if Gardenbug owned.', 'Supervised.', 'good', ARRAY[]::text[], 'none'),
    ('cat_teethers', 1, 1, 'visible', true, false, 'Best for classic natural rubber', 'Sophie La Girafe Original Teether', 'Sophie La Girafe', 'Ocado', 'https://www.ocado.com/products/sophie-la-girafe-original-teether/78496011', NULL, '£15.99', 'in_stock', 'From birth', 'The original Sophie La Girafe natural rubber teether with soft chewable limbs and a gentle squeak, presented for early gumming when everything starts heading to the mouth.', 'Mouthing ramps up hard at four to six months as gums get busy. Soft Sophie legs reach sore spots without hard plastic corners. Wipe clean only, and expect her to live in the changing bag. Keep sessions short and stay within arm reach on the floor.', 'Iconic chew for this mouthing stage.', 'Not dishwasher safe.', 'buy', true, 'Check they do not already own Sophie.', 'Very common gift.', 'Supervised; inspect cracks.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_teethers', 2, 2, 'visible', true, true, 'Best for silicone monkey teethers', 'Matchstick Monkey Original Teether (Mint Green)', 'Matchstick Monkey', 'Ocado', 'https://www.ocado.com/products/matchstick-monkey-original-teether-mint-green/619524011', NULL, '£10.99', 'in_stock', 'From 3 months', 'A Matchstick Monkey silicone teether with easy grip arms and textured bumps for gums, dishwasher and steriliser friendly for the heavy mouthing stretch at this age.', 'Parents who want dishwasher friendly teethers often bounce off Sophie wipe only rules. Matchstick Monkey bumps massage gums and the arms stay grabable when fists are still clumsy. Chill in the fridge if that helps your baby on a sore day.', 'Hygiene-first silicone chew.', 'From 3 months on listing.', 'buy', true, 'Practical gift.', 'One monkey is usually enough.', 'Supervised; 3m+.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_teethers', 3, 3, 'visible', true, true, 'Best for textured Sophie rings', 'Sophie la Girafe So Pure Soft Teether', 'Sophie La Girafe', 'Coolshop', 'https://www.coolshop.co.uk/product/sophie-la-girafe-so-pure-teether-soft-200318/A4G7JH/', NULL, 'See Hamleys', 'in_stock', 'From birth', 'A Sophie la Girafe So Pure soft teething ring with two textured rings, light for small hands to lift and mouth on the playmat during floor play.', 'Not every baby loves the classic giraffe shape. This soft ring keeps Sophie rubber feel with more textures to work along the gum line. Treat it as Sophie number two, not Sophie number three in the same changing bag basket this month.', 'Alternate Sophie geometry.', 'Sophie brand cap.', 'buy', true, 'If original Sophie owned.', 'Max two Sophie.', 'Surface clean.', 'good', ARRAY[]::text[], 'none'),
    ('cat_teethers', 4, 4, 'visible', true, true, 'Best for several chew pieces', 'Playgro Jungle Friends Gift Pack', 'Playgro', 'Coolshop UK', 'https://www.coolshop.co.uk/product/playgro-jungle-friends-gift-pack-10182436/AD6X5Q/', NULL, '£23.00', 'in_stock', '0 months+', 'A Playgro Jungle Friends pack that includes three textured linking teethers alongside wrist and foot pieces, so you can rotate chews when one is in the wash.', 'Teething weeks mean lost teethers under sofas. A pack with several chew links keeps a clean one ready without another emergency shop run. Start with the linking teethers on the mat before adding the soft foot pieces if hands are the main job today.', 'Backup chews in one box.', 'Not a single hero teether.', 'buy', true, 'Useful multi gift.', 'Skip if many teethers already.', 'Supervised.', 'good', ARRAY[]::text[], 'none'),
    ('cat_teethers', 5, 5, 'visible', true, true, 'Best for crinkle chew toys', 'Lamaze Flip Flap Dragon Rattle', 'Lamaze', 'Coolshop UK', 'https://www.coolshop.co.uk/product/lamaze-flip-flap-dragon-rattle-941-275651/AM3X6F/', NULL, 'See Coolshop', 'in_stock', '0 months+', 'A Lamaze Flip Flap Dragon soft rattle with crinkly feet and a clip that flaps the wings, giving a mouthable soft toy when gums want fabric as well as rubber.', 'Some babies chew fabric as hard as silicone. Flip Flap offers crinkle feet and a soft body when rubber teethers are rejected for an hour. Keep a proper silicone or rubber teether as the main gum tool beside it on the mat.', 'Fabric chew alternative.', 'Not a primary gum massager.', 'buy', true, 'Secondary chew toy.', 'Pair with Sophie or Matchstick.', 'Supervised.', 'good', ARRAY[]::text[], 'none'),
    ('cat_tummy_time_mat', 1, 1, 'visible', true, false, 'Best for longer tummy sessions', 'The Play Gym', 'Lovevery', 'Lovevery UK', 'https://lovevery.co.uk/products/the-play-gym', NULL, '£140.00', 'in_stock', '0–12 months+', 'A washable organic cotton floor gym with a wooden frame, hanging toys and a play guide that moves from short tummy spells into reaching and rolling on the living room floor.', 'By four to six months the floor becomes a proper workout space, not a quick stretch on a towel. This gym keeps tummy time interesting with reachables that change as rolling starts. The washable mat survives milk dribbles without turning the room into a plastic play zone for every awake spell.', 'Longer tummy sessions plus intentional reaching as rolling begins.', 'Premium; one gym is usually enough.', 'buy', true, 'Big first-year gift - check they lack a large gym.', 'High ownership risk if a gym already lives downstairs.', 'Awake supervised floor play only.', 'strong', ARRAY[]::text[], 'check_claim'),
    ('cat_tummy_time_mat', 2, 2, 'visible', true, true, 'Best for wipe-clean living mats', 'The Mariner Playmat', 'Totter + Tumble', 'Totter + Tumble', 'https://totterandtumble.co.uk/products/the-mariner-playmat', NULL, '£160.00', 'in_stock', 'Safe and certified for newborns', 'A reversible Totter and Tumble floor mat with a soft cushioned core and a wipe-clean surface, sized so you can sit beside them for longer tummy sessions without hard boards underneath.', 'Once tummy time lasts more than a minute, cold floors punish elbows and knees. A wipe-clean cushioned mat lets you join them on the floor without a giant foam puzzle. Reversible faces keep it looking intentional when visitors walk through after lunch on a busy day.', 'Clean supportive surface for floor-as-gym without arches.', 'Premium price.', 'buy', true, 'Stylish long-life mat gift.', 'Skip if a thick wipe-clean mat already covers the main zone.', 'Supervised awake play only.', 'strong', ARRAY[]::text[], 'none'),
    ('cat_tummy_time_mat', 3, 3, 'visible', true, true, 'Best for modular foam patches', 'Rainbow Playmat Set in Cream', 'Gus + Beau', 'Gus + Beau', 'https://www.gusandbeau.com/products/rainbow-playmat-set-in-cream', NULL, '£75.00', 'in_stock', 'Suitable for children of all ages (supervised)', 'A thick non-toxic EVA foam puzzle playmat in a simple cream rainbow design, so you can build a soft patch on hard floors and pull tiles apart after spills.', 'Hard tiles punish longer tummy spells once they push up and rock. Puzzle foam softens the floor without covering the whole room in one roll. Pull one tile aside after a spill and the rest of the patch stays ready for the next try on the same afternoon.', 'Modular padding for smaller homes.', 'Seams collect crumbs.', 'buy', true, 'Practical gift for hard-floor flats.', 'Avoid a second foam set if tiles already cover the corner.', 'Supervised play.', 'good', ARRAY[]::text[], 'none'),
    ('cat_tummy_time_mat', 4, 4, 'visible', true, true, 'Best for plain expandable tiles', 'Plain Playmat Set in Navy, Sage and Cream', 'Gus + Beau', 'Gus + Beau', 'https://www.gusandbeau.com/products/plain-playmat-set-in-navy-sage-cream', NULL, 'From £75.00', 'in_stock', 'Suitable for children of all ages (supervised)', 'A Gus and Beau plain EVA foam tile set in navy, sage and cream that expands with extra tiles, giving a soft patch for tummy time on hard floors without busy prints.', 'Busy prints can feel loud once the mat stays down all day. Plain tiles keep the floor soft while the room still looks like a living room. Add tiles later if rolling turns into crawling and the soft patch needs to grow with them.', 'Calmer look for open-plan rooms.', 'Plain tiles may not join patterned sets.', 'buy', true, 'Good if they want quiet colours.', 'Do not buy alongside Rainbow unless expanding deliberately.', 'Supervised play.', 'good', ARRAY[]::text[], 'none'),
    ('cat_tummy_time_mat', 5, 5, 'visible', true, true, 'Best for alternate Totter prints', 'The Ludo Playmat', 'Totter + Tumble', 'Totter + Tumble', 'https://totterandtumble.co.uk/products/the-ludo-playmat', NULL, 'From £160.00', 'in_stock', 'Safe and certified for newborns', 'A Totter and Tumble Ludo reversible wipe-clean playmat with the same soft cushion as Mariner, offered in a different double sided print for the main floor zone.', 'Some parents want the Totter wipe-clean feel but not the Mariner colours. Ludo keeps the same cushion for longer tummy sessions as rolling starts. Pick one Totter mat only; two large mats in the same home usually just fight for floor space.', 'Print choice within a proven wipe-clean mat.', 'Do not double-buy with Mariner.', 'buy', true, 'Only if they lack a Totter mat.', 'High duplication risk with Mariner.', 'Supervised awake play only.', 'good', ARRAY[]::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '4-6m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-24T11:05:58.403Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '4-6m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

